 // provided payment successfully\n  Complete = "complete",\n}\n')),(0,i.kt)("p",null,"\u0110\u1ecbnh ngh\u0129a cho order model."),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// src/models/order.ts\nimport mongoose from "mongoose";\n\ninterface OrderAttrs {\n  userId: string;\n  status: OrderStatus;\n  expiresAt: Date;\n  ticket: TicketDoc;\n}\n\ninterface OrderDoc extends mongoose.Document {\n  userId: string;\n  status: OrderStatus;\n  expiresAt: Date;\n  ticket: TicketDoc;\n}\n\ninterface OrderModel extends mongoose.Model<OrderDoc> {\n  build(attrs: OrderAttrs): OrderDoc;\n}\n\nconst orderSchema = new mongoose.Schema(\n  {\n    userId: {\n      type: String,\n      require: true,\n    },\n    status: {\n      type: String,\n      require: true,\n      enum: Object.values(OrderStatus),\n      default: OrderStatus.Created,\n    },\n    expiresAt: {\n      type: mongoose.Schema.Types.Date,\n    },\n\n    ticket: {\n      type: mongoose.Schema.Types.ObjectId,\n      ref: "Ticket",\n      required: true,\n    },\n  },\n  {\n    toJSON: {\n      transform(doc, ret) {\n        ret.id = ret._id;\n        delete ret._id;\n        delete ret.__v;\n      },\n    },\n  },\n);\n\norderSchema.statics.build = (attrs: OrderAttrs) => {\n  return new Order(attrs);\n};\n\nconst Order = mongoose.model<OrderDoc, OrderModel>("Order", orderSchema);\n\nexport { Order };\n')),(0,i.kt)("p",null,"\u0110\u1ecbnh ngh\u0129a cho ticket model"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// src/models/ticket\nimport mongoose from "mongoose";\n\ninterface TicketAttrs {\n  title: string;\n  price: number;\n}\n\ninterface TicketDoc extends mongoose.Document {\n  title: string;\n  price: number;\n}\n\ninterface TicketModel extends mongoose.Model<TicketDoc> {\n  build(attrs: TicketAttrs): TicketDoc;\n}\n\nconst ticketSchema = new mongoose.Schema(\n  {\n    title: {\n      type: String,\n      required: true,\n    },\n    price: {\n      type: Number,\n      required: true,\n    },\n  },\n  {\n    toJSON: {\n      transform(doc, ret) {\n        ret.id = ret._id;\n        delete ret._id;\n        delete ret.__v;\n      },\n    },\n  },\n);\n\nticketSchema.statics.build = (attrs: TicketAttrs) => {\n  return new Ticket(attrs);\n};\n\nconst Ticket = mongoose.model<TicketDoc, TicketModel>("Ticket", ticketSchema);\n\nexport { Ticket };\n')),(0,i.kt)("h2",{id:"order-creation-logic"},"Order Creation Logic"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// src/routes/create.ts\nconst router = express.Router();\nrouter.post(\n  "/api/orders",\n  requireAuth,\n  [\n    body("ticketID")\n      .not()\n      .isEmpty()\n      .custom((input: string) => mongoose.Types.ObjectId.isValid(input))\n      .withMessage("TicketID must be provided"),\n  ],\n  validateRequest,\n  async (req: Request, res: Response) => {\n    const { ticketID } = req.body;\n\n    // Find the ticket the user is trying to order in the database\n    const ticket = await Ticket.findById(ticketID);\n    if (!ticket) {\n      throw new NotFoundError();\n    }\n\n    // Make sure that this ticket is not already reserved\n    // Run the query to look at all orders. Find an order where the ticket\n    // is the ticket we just found and the orders status is not cancelled\n    // If we find and order from that means the ticket is reserved\n    const isReserved = await ticket.isReserved();\n    if (isReserved) {\n      throw new BadRequestError("Ticket is already reserved.");\n    }\n\n    // Calculate an expiration date for this order\n    const expiration = new Date();\n    expiration.setSeconds(expiration.getSeconds() + EXPIRATION_WINDOW_SECOND);\n\n    // Build the order and save it to the database\n    const order = Order.build({\n      userId: req.currentUser!.id,\n      status: OrderStatus.Created,\n      expiresAt: expiration,\n      ticket,\n    });\n\n    await order.save();\n\n    // Publish and event saying that an order was created\n    res.status(201).send(order);\n  },\n);\n\nexport { router as createOrderRouter };\n')),(0,i.kt)("h2",{id:"convenience-document-methods"},"Convenience Document Methods"),(0,i.kt)("p",null,"Add new methods to ticket model"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},"// src/models/ticket.ts\nexport interface TicketDoc extends mongoose.Document {\n  title: string;\n  price: number;\n  isReserved(): Promise<boolean>;\n}\n\nticketSchema.methods.isReserved = async function () {\n  // this === the ticket document\n  const existingOrder = await Order.findOne({\n    ticket: this.id,\n    status: {\n      $in: [\n        OrderStatus.Created,\n        OrderStatus.AwaitingPayment,\n        OrderStatus.Complete,\n      ],\n    },\n  });\n  return !!existingOrder;\n};\n")),(0,i.kt)("h2",{id:"test-setup"},"Test Setup"),(0,i.kt)("p",null,"Copy ",(0,i.kt)("inlineCode",{parentName:"p"},"test")," folder v\xe0 ",(0,i.kt)("inlineCode",{parentName:"p"},"__mocks__")," folder"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// create.test.ts\nit("returns an error if the ticket does not exist", async () => {\n  const ticketID = new mongoose.Types.ObjectId().toHexString();\n\n  await request(app)\n    .post("/api/orders")\n    .set("Cookie", global.signin())\n    .send({ ticketID })\n    .expect(404);\n});\n\nit("returns an error if the ticket is already reserved", async () => {\n  const ticket = Ticket.build({ title: "concert", price: 20 });\n  await ticket.save();\n\n  const order = Order.build({\n    ticket,\n    userId: "dvbgrtf",\n    status: OrderStatus.Created,\n    expiresAt: new Date(),\n  });\n  await order.save();\n\n  await request(app)\n    .post("/api/orders")\n    .set("Cookie", global.signin())\n    .send({ ticketID: ticket.id })\n    .expect(400);\n});\n\nit("reserved a ticket", async () => {\n  const ticket = Ticket.build({ title: "concert", price: 20 });\n  await ticket.save();\n\n  await request(app)\n    .post("/api/orders")\n    .set("Cookie", global.signin())\n    .send({ ticketID: ticket.id })\n    .expect(201);\n});\n\nit.todo("emits an order created event");\n')),(0,i.kt)("h2",{id:"fetching-a-users-orders"},"Fetching a User's Orders"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// src/routes/read.ts\nrouter.get("/api/orders", requireAuth, async (req: Request, res: Response) => {\n  const orders = await Order.find({ userId: req.currentUser!.id }).populate(\n    "ticket",\n  );\n\n  res.send(orders);\n});\n')),(0,i.kt)("h2",{id:"a-slightly-complicated-test"},"A slightly Complicated Test"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// read.test.ts\n\nconst buildTicket = async () => {\n  const ticket = Ticket.build({ title: "concert", price: 20 });\n\n  await ticket.save();\n\n  return ticket;\n};\n\nit("fetches orders for an particular user", async () => {\n  // Create three tickets\n  const ticketOne = await buildTicket();\n  const ticketTwo = await buildTicket();\n  const ticketThree = await buildTicket();\n\n  const userOne = global.signin();\n  const userTwo = global.signin();\n  // \u1ede \u0111\xe2y h\xe0m signin s\u1ebd \u0111\u01b0\u1ee3c update 1 t\xed \u0111\u1ec3 random userId. B\u1ea1n c\xf3 th\u1ec3 s\u1eed d\u1ee5ng l\u1ea1i logic c\u1ee7a ticketID\n\n  // Create one order as User #1\n  await request(app)\n    .post("/api/orders")\n    .set("Cookie", userOne)\n    .send({ ticketID: ticketOne.id })\n    .expect(201);\n\n  // Create two orders as User #2\n  const { body: orderOne } = await request(app)\n    .post("/api/orders")\n    .set("Cookie", userTwo)\n    .send({ ticketID: ticketTwo.id })\n    .expect(201);\n  const { body: orderTwo } = await request(app)\n    .post("/api/orders")\n    .set("Cookie", userOne)\n    .send({ ticketID: ticketThree.id })\n    .expect(201);\n\n  // Make request to get orders for User #2\n  const res = await request(app)\n    .get("/api/orders")\n    .set("Cookie", userTwo)\n    .expect(200);\n\n  // Make sure we only got the orders for User #2\n  expect(res.body.length).toEqual(2);\n  expect(res.body[0].id).toEqual(orderOne.id);\n  expect(res.body[1].id).toEqual(orderTwo.id);\n});\n')),(0,i.kt)("h2",{id:"fetching-individual-order"},"Fetching Individual Order"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'router.get(\n  "/api/orders/:id",\n  requireAuth,\n  async (req: Request, res: Response) => {\n    const order = await Order.findById(req.params.id).populate("ticket");\n\n    if (!order) {\n      throw new NotFoundError();\n    }\n\n    if (order.userId !== req.currentUser!.id) {\n      throw new NotAuthorizedError();\n    }\n\n    res.send(order);\n  },\n);\n')),(0,i.kt)("p",null,"Test"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'it("fetches the order", async () => {\n  // Create a ticket\n  const ticket = await buildTicket();\n\n  const user = global.signin();\n  // make a request to build an order with this ticket\n  const { body: order } = await request(app)\n    .post("/api/orders")\n    .set("Cookie", user)\n    .send({ ticketID: ticket.id })\n    .expect(201);\n\n  // make request to fetch the order\n  const { body: fetchedOrder } = await request(app)\n    .get(`/api/orders/${order.id}`)\n    .set("Cookie", user)\n    .send()\n    .expect(200);\n\n  expect(fetchedOrder.id).toEqual(order.id);\n});\n\nit("returns an error if one user tries to fetch anothers order", async () => {\n  // Create a ticket\n  const ticket = await buildTicket();\n\n  const user = global.signin();\n  // make a request to build an order with this ticket\n  const { body: order } = await request(app)\n    .post("/api/orders")\n    .set("Cookie", user)\n    .send({ ticketId: ticket.id })\n    .expect(201);\n\n  // make request to fetch the order\n  const { body: fetchedOrder } = await request(app)\n    .get(`/api/orders/${order.id}`)\n    .set("Cookie", global.signin())\n    .send()\n    .expect(401);\n});\n')),(0,i.kt)("h2",{id:"cancelling-an-order"},"Cancelling An Order"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// src/routes/delete.ts\nrouter.delete(\n  "/api/orders/:orderID",\n  requireAuth,\n  async (req: Request, res: Response) => {\n    const { orderID } = req.params;\n    const order = await Order.findById(orderID);\n\n    if (!order) {\n      throw new NotFoundError();\n    }\n    if (order.userId !== req.currentUser!.id) {\n      throw new NotAuthorizedError();\n    }\n    order.status = OrderStatus.Cancelled;\n    await order.save();\n\n    // publishing an event saying this was cancelled\n\n    res.status(204).send(order);\n  },\n);\n')),(0,i.kt)("h2",{id:"test-cancel"},"Test Cancel"),(0,i.kt)("pre",null,(0,i.kt)("code",{parentName:"pre",className:"language-ts"},'// delete.test.ts\nit("makrs an order as cancelled", async () => {\n  // create a ticket with Ticket Model\n  const ticket = await buildTicket();\n\n  const user = global.signin();\n  // make a request to create an order\n  const { body: order } = await request(app)\n    .post("/api/orders")\n    .set("Cookie", user)\n    .send({ ticketID: ticket.id })\n    .expect(201);\n\n  // make a request to cancel the order\n  await request(app)\n    .delete(`/api/orders/${order.id}`)\n    .set("Cookie", user)\n    .send()\n    .expect(204);\n\n  // expectation to make sure the thing is cancelled\n  const updatedOrder = await Order.findById(order.id);\n\n  expect(updatedOrder!.status).toEqual(OrderStatus.Cancelled);\n});\n\nit.todo("emits an event saying this order was cancelled");\n')))}p.isMDXComponent=!0},59766:function(e,n,t){n.Z=t.p+"assets/images/microservices-dg-198-60be2a234c2916fb30b01aee845b7bed.png"},10530:function(e,n,t){n.Z=t.p+"assets/images/microservices-dg-199-3bd20884dff85e44edf8a2abf7153935.png"},78214:function(e,n,t){n.Z=t.p+"assets/images/microservices-dg-200